class Order(BaseModel):
    subtotal: float
    tax_pct: float

    def total(self) -> float:
        return self.subtotal * (1 + self.tax_pct)

def test_export_ordering():
    rows = export_all(db)
    assert rows == sorted(rows, key=lambda r: r['id'])

def export_all(db):
    cur = db.execute('SELECT * FROM rows')
    return [dict(r) for r in cur.fetchall()]

